mapper.select:
SELECT mp.*, sc.nick_name, sc.username, sc.avatar_url, sc.country, sc.account, sc.platform_type, mt.template_name FROM store_message_push_detail mp LEFT JOIN store_celebrity sc ON mp.kol_id = sc.id LEFT JOIN store_message_template mt on mp.message_tel_type = mt.id where 1=1
and mp.seller_id = #{messagePushDetailModel.sellerId}
and mp.kol_email = #{messagePushDetailModel.kolEmail}
and mt.template_name like '%${messagePushDetailModel.templateName}%'
and sc.nick_name like '%${messagePushDetailModel.kolName}%'
and mp.send_email like '%${messagePushDetailModel.sendEmail}%'
and mp.is_confirm = #{messagePushDetailModel.isConfirm}
and mp.is_confirm >= #{messagePushDetailModel.isConfirm}
and DATE_FORMAT(mp.create_time, '%Y-%m-%d') = DATE_FORMAT(#{messagePushDetailModel.createDate}, '%Y-%m-%d')
and DATE_FORMAT(mp.email_push_date, '%Y-%m-%d') = DATE_FORMAT(#{messagePushDetailModel.emailPushTime}, '%Y-%m-%d')
and mp.is_send = #{messagePushDetailModel.isSend}
and DATE_FORMAT(mp.email_push_date, '%Y-%m-%d') >= DATE_FORMAT(#{messagePushDetailModel.startSendTime}, '%Y-%m-%d')
and DATE_FORMAT(mp.email_push_date, '%Y-%m-%d') <= DATE_FORMAT(#{messagePushDetailModel.endSendTime}, '%Y-%m-%d')
order by create_time desc

select count(1) as count from store_message_push_detail where 1=1

    and is_send != -2


    and is_send = 1


    and kol_id = #{detailModel.kolId}


    and email_push_date like '%${detailModel.emailPushDate}%'


    and seller_id = #{detailModel.sellerId}


    and email_title = #{detailModel.emailTitle}
